// ── UTILITIES ───────────────────────────────────────────────
function showScreen(id) {
  document.querySelectorAll('.screen').forEach(s => s.classList.remove('active'));
  const el = document.getElementById('screen-' + id);
  if (el) el.classList.add('active');
  window.scrollTo(0, 0);
}

function toggleLang() {
  lang = lang === 'en' ? 'bm' : 'en';

  // Update ALL lang toggle buttons on the page
  document.querySelectorAll('.lang-btn').forEach(btn => {
    btn.textContent = lang === 'en' ? 'BM' : 'EN';
  });

  // Persist preference so other pages can read it
  try { localStorage.setItem('naik_lang', lang); } catch(e) {}

  applyLang();

  const active = document.querySelector('.screen.active')?.id;
  if (active === 'screen-onboarding') {
    renderStep();
  } else if (active === 'screen-roadmap' && roadmapData) {
    // The career path CONTENT (titles, job names, phase text) came from the backend
    // in the original language. We must re-fetch to get the translated content.
    // Re-use the same profile — just change the lang param sent to the backend.
    if (profile && profile.name) {
      _refetchRoadmapForLang();
    }
  }
}

async function _refetchRoadmapForLang() {
  // Show a subtle in-place loading state instead of the full spinner screen
  const wasFullOpen  = _fullRoadmapOpen;
  const wasPathIdx   = selectedPath;

  // Brief overlay so user sees something is happening
  const overlay = document.createElement('div');
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(250,248,245,0.7);z-index:500;display:flex;align-items:center;justify-content:center;backdrop-filter:blur(2px)';
  overlay.innerHTML = `<div style="text-align:center"><div style="font-size:1.4rem;font-weight:800;color:#BF4646;font-family:'Playfair Display',serif">NAIK</div><div style="margin-top:8px;font-size:0.85rem;color:#6B6B80">${lang==='en'?'Switching language…':'Menukar bahasa…'}</div></div>`;
  document.body.appendChild(overlay);

  try {
    const res = await fetch('/api/generate-roadmap', {
      method:  'POST',
      headers: { 'Content-Type': 'application/json' },
      body:    JSON.stringify({ profile, lang }),
      signal:  AbortSignal.timeout(12000)
    });
    if (!res.ok) throw new Error('refetch failed');
    const data = await res.json();
    if (data.careerPaths?.length) {
      roadmapData  = data;
      selectedPath = wasPathIdx;
    }
  } catch(e) {
    // On failure, still re-render with old data (UI chrome at least switches)
    console.warn('[NAIK] Lang re-fetch failed, re-rendering with cached data:', e.message);
  }

  document.body.removeChild(overlay);

  if (wasFullOpen && roadmapData.careerPaths[wasPathIdx]) {
    renderFullRoadmap(roadmapData.careerPaths[wasPathIdx]);
  } else {
    renderPathSelection();
  }
}

function applyLang() {
  document.querySelectorAll('[data-en]').forEach(el => {
    el.textContent = el.getAttribute('data-' + lang);
  });
}

function showToast(msg, duration = 3000) {
  const t = document.getElementById('toast');
  if (!t) return;
  t.textContent = msg;
  t.classList.add('show');
  setTimeout(() => t.classList.remove('show'), duration);
}

