// ── RENDER QUIZ STEP ─────────────────────────────────────────
function renderStep() {
  const steps = getSteps();
  const s     = steps[step];
  const t     = T[lang];
  const total = steps.length;

  document.getElementById('step-count').textContent = `${step + 1} / ${total}`;
  document.getElementById('progress-fill').style.width = `${((step + 1) / total) * 100}%`;
  document.getElementById('step-hint').textContent = s.hint ? s.hint[lang] : '';
  document.getElementById('btn-back-header').style.display = step > 0 ? 'block' : 'none';

  let html = `<div class="fade-up">
    <div class="q-label">${lang==='en'?'Step':'Langkah'} ${step + 1}</div>
    <div class="q-text">${s.label[lang]}</div>`;

  if (s.type === 'text') {
    html += `<div class="text-input-wrap">
      <input type="text" id="q-input" value="${profile[s.id]||''}" placeholder="${s.placeholder[lang]}"
        oninput="profile['${s.id}']=this.value.trim();document.getElementById('btn-next').disabled=!this.value.trim()"/>
    </div>`;
  } else if (s.type === 'select') {
    html += `<div class="option-grid single-col">`;
    s.options.forEach(o => {
      html += `<button class="option-btn${profile[s.id]===o.val?' selected':''}" onclick="selOpt('${s.id}','${o.val}',this)">
        <span class="opt-title">${o.label[lang]}</span></button>`;
    });
    html += `</div>`;
  } else if (s.type === 'options') {
    html += `<div class="option-grid">`;
    s.options.forEach(o => {
      html += `<button class="option-btn${profile[s.id]===o.val?' selected':''}" onclick="selOpt('${s.id}','${o.val}',this)">
        <span class="opt-icon">${o.icon}</span>
        <span><span class="opt-title">${o.label[lang]}</span><span class="opt-sub">${o.sub[lang]}</span></span>
      </button>`;
    });
    html += `</div>`;
  } else if (s.type === 'checkbox') {
    html += `<div class="option-grid single-col">`;
    s.options.forEach(o => {
      const checked = (profile[s.id]||[]).includes(o.val);
      html += `<button class="option-btn${checked?' selected':''}" onclick="togCb('${s.id}','${o.val}',this)">
        <span class="opt-title">${o.label[lang]}</span></button>`;
    });
    html += `</div>`;
  } else if (s.type === 'mode') {
    html += `
    <div class="mode-option${profile.income_mode==='immediate'?' selected':''}" onclick="selMode('immediate',this)">
      <div class="mode-option-top"><div class="mode-icon">⚡</div>
        <div class="mode-title">${lang==='en'?'I need income NOW':'Saya perlukan pendapatan SEKARANG'}</div></div>
      <div class="mode-desc">${lang==='en'
        ? "I can't afford to wait. Show me jobs I can apply for today — no experience needed — and I'll build skills on the side."
        : "Saya tidak mampu menunggu. Tunjukkan kerja yang boleh saya mohon hari ini — tiada pengalaman diperlukan — dan saya akan bina kemahiran sambil bekerja."}</div>
    </div>
    <div class="mode-option${profile.income_mode==='upskill'?' selected':''}" onclick="selMode('upskill',this)">
      <div class="mode-option-top"><div class="mode-icon">🎓</div>
        <div class="mode-title">${lang==='en'?'I can invest 1–3 months to learn first':'Saya boleh luangkan 1–3 bulan untuk belajar dulu'}</div></div>
      <div class="mode-desc">${lang==='en'
        ? "I can manage for a few months. I want to get a free certification first so I qualify for better-paying jobs right away."
        : "Saya boleh bertahan beberapa bulan. Saya ingin mendapatkan sijil percuma dahulu supaya saya layak untuk kerja bergaji lebih baik."}</div>
    </div>`;
  }

  const hasVal = s.type==='text' ? !!(profile[s.id]||'').trim()
               : s.type==='checkbox' ? true
               : !!profile[s.id];

  html += `<div class="nav-row">
    ${step>0?`<button class="btn-back-step" onclick="goBack()">${t.back}</button>`:''}
    <button class="btn-next-step" id="btn-next" onclick="goNext()" ${!hasVal?'disabled':''}>
      ${step===steps.length-1?t.generate:t.next}
    </button>
  </div></div>`;

  document.getElementById('onboard-body').innerHTML = html;

  if (s.type === 'text') {
    const inp = document.getElementById('q-input');
    if (inp) { inp.focus(); inp.addEventListener('keydown', e => { if(e.key==='Enter') goNext(); }); }
  }
}

function selOpt(k, v, el) {
  profile[k] = v;
  el.closest('.option-grid').querySelectorAll('.option-btn').forEach(b => b.classList.remove('selected'));
  el.classList.add('selected');
  document.getElementById('btn-next').disabled = false;
}
function selMode(v, el) {
  profile.income_mode = v;
  document.querySelectorAll('.mode-option').forEach(b => b.classList.remove('selected'));
  el.classList.add('selected');
  document.getElementById('btn-next').disabled = false;
}
function togCb(k, v, el) {
  if (!profile[k]) profile[k] = [];
  const a = profile[k], i = a.indexOf(v);
  if (i>=0) { a.splice(i,1); el.classList.remove('selected'); }
  else       { a.push(v);    el.classList.add('selected'); }
}
function goBack() { if(step>0){step--;renderStep();} }
function goNext() {
  const s = getSteps()[step];
  if(s.type==='text' && !(profile[s.id]||'').trim()) return;
  if(step<getSteps().length-1){step++;renderStep();}
  else generateRoadmap();
}


// ── ROADMAP GENERATION ───────────────────────────────────────
// Calls the Flask backend which queries your Supabase jobs database.
// The backend scores & ranks jobs by how well they match the user's profile.
// No AI needed — all content comes from your database rows.

async function generateRoadmap() {
  showScreen('generating');
  const t = T[lang];
  let mi = 0;
  const msgEl = document.getElementById('gen-msg');
  msgEl.textContent = t.genMsgs[0];
  const iv = setInterval(() => {
    if (mi < t.genMsgs.length - 1) msgEl.textContent = t.genMsgs[++mi];
  }, 2000);

  try {
    const res = await fetch('/api/generate-roadmap', {
      method:  'POST',
      headers: { 'Content-Type': 'application/json' },
      body:    JSON.stringify({ profile, lang }),
      signal:  AbortSignal.timeout(12000)
    });

    clearInterval(iv);

    if (!res.ok) {
      const errText = await res.text();
      throw new Error('Server error ' + res.status + ': ' + errText.slice(0, 200));
    }

    const data = await res.json();
    if (data.error) throw new Error(data.error);
    if (!data.careerPaths?.length) throw new Error('No career paths returned from database. Please seed your Supabase jobs table.');

    roadmapData  = data;
    selectedPath = 0;
    renderPathSelection();

  } catch (err) {
    clearInterval(iv);
    console.error('[NAIK]', err.message);
    const screen = document.getElementById('screen-generating');
    screen.innerHTML =
      '<div class="gen-inner">' +
        '<div class="gen-logo">NAIK</div>' +
        '<div style="font-size:2rem;margin:1rem 0">⚠️</div>' +
        '<p class="gen-msg" style="color:#BF4646">' +
          (lang === 'en'
            ? 'Could not load your roadmap. Please check your connection and try again.<br><small style="opacity:.7">' + err.message + '</small>'
            : 'Tidak dapat memuatkan peta jalan. Sila semak sambungan anda dan cuba lagi.<br><small style="opacity:.7">' + err.message + '</small>') +
        '</p>' +
        '<button class="btn btn-primary" onclick="restartApp()" style="margin-top:1.5rem">' +
          (lang === 'en' ? '↺ Try Again' : '↺ Cuba Lagi') +
        '</button>' +
      '</div>';
  }
}

// ── PATH SELECTION ───────────────────────────────────────────
function renderPathSelection() {
  const t     = T[lang];
  const paths = roadmapData.careerPaths || [];
  const name  = profile.name || '';
  const isImmediate = profile.income_mode === 'immediate';

  let html = `
  <div class="roadmap-header">
    <div class="roadmap-header-meta">
      <span class="section-label">${t.sectionTitle}</span>
      <div style="display:flex;gap:8px;align-items:center;">
        <button class="btn-restart" onclick="restartApp()">${t.restart}</button>
      </div>
    </div>
    <h1 class="roadmap-title">${t.greeting(name)}</h1>
    <div class="mode-banner ${isImmediate?'immediate':'upskill'}">
      ${isImmediate
        ? `⚡ <strong>${lang==='en'?'Immediate Income Mode':'Mod Pendapatan Segera'}</strong>`
        : `🎓 <strong>${lang==='en'?'Upskill First Mode':'Mod Tingkatkan Kemahiran'}</strong>`}
    </div>
  </div>
  <div class="roadmap-body">
    <div class="path-choose-header">
      <h2 class="path-choose-title">${t.choosePathTitle}</h2>
      <p class="path-choose-sub">${t.choosePathSub}</p>
    </div>
    <div class="path-cards">`;

  const optionLetters = ['A','B','C'];
  const pathClasses   = ['path-a','path-b','path-c'];
  paths.forEach((p, idx) => {
    const safetyClass = p.safetyRating?.includes('Most')?'safety-green': p.safetyRating?.includes('Decent')?'safety-amber':'safety-teal';
    html += `
    <div class="path-card" onclick="selectPath(${idx})">
      <div class="path-card-top">
        <span class="path-emoji">${p.emoji||'🎯'}</span>
        <span class="path-id-badge ${pathClasses[idx]||'path-a'}">Option ${optionLetters[idx]||idx+1}</span>
      </div>
      <div class="path-route-label">${p.title}</div>
      <div class="path-target-job">${p.targetJob}</div>
      <div class="path-tagline">${p.tagline}</div>
      <div class="path-salary-row">
        <div><span class="psl">${lang==='en'?'Start':'Mula'}</span><span class="psv">${p.entrySalary}</span></div>
        <div class="path-arrow">→</div>
        <div><span class="psl">${lang==='en'?'Target':'Sasaran'}</span><span class="psv psv-target">${p.targetSalary}</span></div>
      </div>
      <div class="path-meta-row">
        <span class="path-timeline">⏱ ${p.timeline}</span>
        <span class="path-safety ${safetyClass}">★ ${p.safetyRating}</span>
      </div>
      <button class="path-select-btn">${lang==='en'?'Choose this path →':'Pilih laluan ini →'}</button>
    </div>`;
  });

  html += `</div></div>`;

  const screen = document.getElementById('screen-roadmap');
  screen.innerHTML = html;
  showScreen('roadmap');
  _fullRoadmapOpen = false;
}

function selectPath(idx) {
  selectedPath = idx;
  const path = roadmapData.careerPaths[idx];
  renderFullRoadmap(path);
}

// ── FULL ROADMAP ─────────────────────────────────────────────
